class Solution:
    def minDays(self, bloomDay, m, k):
        n = len(bloomDay)
        if m * k > n:
            return -1

        def feasible(day):
            count = 0
            groups = 0
            for b in bloomDay:
                if b <= day:
                    count += 1
                    if count == k:
                        groups += 1
                        count = 0
                else:
                    count = 0
            return groups >= m

        for day in range(min(bloomDay), max(bloomDay) + 1):
            if feasible(day):
                return day
        return -1

