var minDays = function(bloomDay, m, k) {
    const n = bloomDay.length;
    if (m * k > n) return -1;
    function feasible(day) {
        let count = 0, groups = 0;
        for (const b of bloomDay) {
            if (b <= day) {
                count += 1;
                if (count === k) {
                    groups += 1;
                    count = 0;
                }
            } else {
                count = 0;
            }
        }
        return groups >= m;
    }
    let lo = bloomDay[0], hi = bloomDay[0];
    for (const b of bloomDay) {
        if (b < lo) lo = b;
        if (b > hi) hi = b;
    }
    while (lo < hi) {
        const mid = lo + Math.floor((hi - lo) / 2);
        if (feasible(mid)) {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    return lo;
};
